CREATE TABLE SALA (
    ID_sali INTEGER PRIMARY KEY,
    numer_sali INTEGER,
    ilosc_miejsc INTEGER
);

CREATE TABLE SCENERIA (
    ID_scenerii INTEGER PRIMARY KEY,
    krotki_opis_scenerii VARCHAR2(80)
);

CREATE TABLE SPEKTAKL (
    ID_spektaklu INTEGER PRIMARY KEY,
    tytul_spektaklu VARCHAR2(80)
);

CREATE TABLE PRZEDSTAWIENIE (
    ID_przedstawienia INTEGER PRIMARY KEY,
    data_przedstawienia DATE,
    godzina_przedstawienia DATE,
    SALA_id_sali INTEGER,
    SCENERIA_id_scenerii INTEGER,
    SPEKTAKL_id_spektaklu INTEGER,
    FOREIGN KEY (SALA_id_sali) REFERENCES SALA(ID_sali),
    FOREIGN KEY (SCENERIA_id_scenerii) REFERENCES SCENERIA(ID_scenerii),
    FOREIGN KEY (SPEKTAKL_id_spektaklu) REFERENCES SPEKTAKL(ID_spektaklu)
);

CREATE TABLE ZAWOD (
    ID_zawodu INTEGER PRIMARY KEY,
    nazwa_zawodu VARCHAR2(80)
);

CREATE TABLE PRACOWNICY_TEATRU (
    ID_pracownika INTEGER PRIMARY KEY,
    imie_pracownika VARCHAR2(30),
    nazwisko_pracownika VARCHAR2(50),
    ZAWOD_id_zawodu INTEGER,
    FOREIGN KEY (ZAWOD_id_zawodu) REFERENCES ZAWOD(ID_zawodu)
);

CREATE TABLE PRZEDSTAWIENIE_PRACOWNIK (
    ID_przedstawienie_pracownik INTEGER PRIMARY KEY,
    PRZEDSTAWIENIE_ID_przedstawienia INTEGER,
    PRACOWNICY_TEATRU_ID_pracownika INTEGER,
    ID_zawodu INTEGER,
    FOREIGN KEY (PRZEDSTAWIENIE_ID_przedstawienia) REFERENCES PRZEDSTAWIENIE(ID_przedstawienia),
    FOREIGN KEY (PRACOWNICY_TEATRU_ID_pracownika) REFERENCES PRACOWNICY_TEATRU(ID_pracownika),
    FOREIGN KEY (ID_zawodu) REFERENCES ZAWOD(ID_zawodu)
);

CREATE TABLE KLIENCI (
    ID_klienta INTEGER PRIMARY KEY,
    imie_klienta VARCHAR2(30),
    nazwisko_klienta VARCHAR2(50),
    numer_telefonu VARCHAR2(15)
);

CREATE TABLE BILETY (
    ID_biletu INTEGER PRIMARY KEY,
    koszt_biletu NUMBER(7,2),
    rodzaj_transakcji VARCHAR2(20),
    rodzaj_platnosci VARCHAR2(20),
    znizka VARCHAR2(20),
    PRZEDSTAWIENIE_ID_przedstawienia INTEGER,
    KLIENCI_ID_klienta INTEGER,
    FOREIGN KEY (PRZEDSTAWIENIE_ID_przedstawienia) REFERENCES PRZEDSTAWIENIE(ID_przedstawienia),
    FOREIGN KEY (KLIENCI_ID_klienta) REFERENCES KLIENCI(ID_klienta)
);

CREATE TABLE REKWIZYT (
    ID_rekwizytu INTEGER PRIMARY KEY,
    nazwa_rekwizytu VARCHAR2(80),
    SCENERIA_id_scenerii INTEGER,
    FOREIGN KEY (SCENERIA_id_scenerii) REFERENCES SCENERIA(ID_scenerii)
);

CREATE TABLE WYNAGRODZENIE (
    ID_wynagrodzenia INTEGER PRIMARY KEY,
    kwota_wynagrodzenia NUMBER(7,2),
    ZAWOD_id_zawodu INTEGER,
    FOREIGN KEY (ZAWOD_id_zawodu) REFERENCES ZAWOD(ID_zawodu)
);




